DROP TABLE IF EXISTS `items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `items` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `government_id` int DEFAULT NULL,
  `city_id` int DEFAULT NULL,
  `place` varchar(255) NOT NULL,
  `date` date NOT NULL,
  `type` enum('lost','found') NOT NULL,
  `description` text,
  `user_id` int NOT NULL,
  `item_category_id` int DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `latitude` decimal(10,8) DEFAULT NULL,
  `longitude` decimal(11,8) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `government_id` (`government_id`),
  KEY `city_id` (`city_id`),
  KEY `user_id` (`user_id`),
  KEY `item_category_id` (`item_category_id`),
  CONSTRAINT `items_ibfk_1` FOREIGN KEY (`government_id`) REFERENCES `governments` (`id`),
  CONSTRAINT `items_ibfk_2` FOREIGN KEY (`city_id`) REFERENCES `cities` (`id`),
  CONSTRAINT `items_ibfk_3` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `items_ibfk_4` FOREIGN KEY (`item_category_id`) REFERENCES `itemcategories` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
