INSERT INTO `messages` VALUES (1,2,1,'Hi, I think I might have seen your lost wallet near Tahrir Square earlier today. It looked just like the picture you uploaded, so I picked it up for you.',0,'2026-04-29 13:14:35'),(2,1,2,'Oh wow, really? Thank you so much! Where can we meet so I can collect it from you?',0,'2026-04-29 13:14:35'),(3,4,3,'I found a phone that might belong to you. The color and model match what you described in your post. I can drop it off at a safe place for you.',0,'2026-04-29 13:14:35'),(4,3,4,'That’s perfect! I appreciate it. I can meet you at the coffee shop near your area to pick it up.',0,'2026-04-29 13:14:35'),(5,1,5,'Is this backpack blue with a laptop inside? I found one near the metro station and it looks important.',0,'2026-04-29 13:14:35'),(6,5,1,'Yes! That’s mine. Thank you for keeping it safe. I can come by your place to get it whenever you’re free.',0,'2026-04-29 13:14:35'),(7,3,2,'I found some keys near Nasr City. They have a small red keychain attached — is that yours?',0,'2026-04-29 13:14:35'),(8,2,3,'Yes, that’s definitely mine. Thank you for finding them. I can meet you at the parking lot near the mall to collect them.',0,'2026-04-29 13:14:35'),(9,5,4,'I believe this is the watch you lost. I picked it up from the bench near the park to keep it safe for you.',0,'2026-04-29 13:14:35'),(10,4,5,'That’s amazing, thanks a lot! The strap and design match perfectly. I can come by to pick it up today.',0,'2026-04-29 13:14:35'),(11,7,6,'Hey, I found a pair of sunglasses that looks like yours at the beach today. I kept them safe for you.',0,'2026-04-29 13:14:35'),(12,6,7,'Oh, perfect! Thank you so much. Can I come by your place to pick them up?',0,'2026-04-29 13:14:35'),(13,9,8,'I think I found your wallet near the bus station. It had a blue cover, right?',0,'2026-04-29 13:14:35'),(14,8,9,'Yes! That’s mine. I really appreciate it. Where can we meet to collect it?',0,'2026-04-29 13:14:35'),(15,11,10,'I found a handbag that matches the description from your post. It’s in good condition.',0,'2026-04-29 13:14:35'),(16,10,11,'Amazing, thank you! Can we meet at the cafe near the metro station to get it?',0,'2026-04-29 13:14:35'),(17,13,12,'I picked up a set of keys that might belong to you. They have a green keychain attached.',0,'2026-04-29 13:14:35'),(18,12,13,'Yes! Those are mine. Thank you for keeping them safe. I can come collect them this afternoon.',0,'2026-04-29 13:14:35'),(19,15,14,'I found your lost scarf near the market. It’s red with white stripes, correct?',0,'2026-04-29 13:14:35'),(20,14,15,'Exactly! Thank you so much. I can come by the market entrance to pick it up.',0,'2026-04-29 13:14:35'),(21,17,16,'I think this backpack belongs to you. Found it near the park entrance.',0,'2026-04-29 13:14:35'),(22,16,17,'Yes! That’s definitely mine. Thanks for keeping it safe. When can I pick it up?',0,'2026-04-29 13:14:35'),(23,19,18,'I found a pair of shoes matching your post. They are black with white stripes.',0,'2026-04-29 13:14:35'),(24,18,19,'Perfect! That’s mine. I appreciate it. I can come by the main street to collect them.',0,'2026-04-29 13:14:35'),(25,21,20,'I found your lost umbrella. It’s blue and has a wooden handle, right?',0,'2026-04-29 13:14:35'),(26,20,21,'Yes, exactly! Thank you! I can meet you near the coffee shop to pick it up.',0,'2026-04-29 13:14:35'),(27,23,22,'I picked up a jacket that might be yours. It’s dark green with a hood.',0,'2026-04-29 13:14:35'),(28,22,23,'Yes, that’s mine. Thanks for keeping it safe. I can come by this evening to get it.',0,'2026-04-29 13:14:35'),(29,25,24,'I found your wallet near the metro station entrance. It looks like the one in your post.',0,'2026-04-29 13:14:35'),(30,24,25,'Awesome! That’s mine. Thank you so much! I can pick it up from your place anytime.',0,'2026-04-29 13:14:35');
